class PeekingIterator:
    def __init__(self, iterator):
        self.it = iterator
        self.buf = None
        self.has_buf = False
        self._fill()
    def _fill(self):
        if not self.has_buf and self.it.hasNext():
            self.buf = self.it.next()
            self.has_buf = True
    def peek(self):
        self._fill()
        return self.buf
    def next(self):
        self._fill()
        val = self.buf
        self.has_buf = False
        self._fill()
        return val
    def hasNext(self):
        return self.has_buf

